import pygame
import random
from collections import namedtuple
from enum import Enum

# Assuming GRID_WIDTH, GRID_HEIGHT, Point, PieceType, TETROMINO_SHAPES, TETROMINO_COLORS, GEM_COLORS, LINE_CLEAR_SCORES, MATCH_CLEAR_SCORES, CHAIN_BONUS_MULTIPLIER, create_empty_grid are defined in task0

class GameState(Enum):
    PLAYING = 0
    GAME_OVER = 1

class TetrisBejeweled:
    def __init__(self, grid_width, grid_height):
        self.grid_width = grid_width
        self.grid_height = grid_height
        self.grid = create_empty_grid()
        self.score = 0
        self.game_state = GameState.PLAYING
        self.chain_reaction = False
        self.chain_multiplier = 1.0

    def detect_matches(self):
        matches = []
        # Horizontal matches
        for y in range(self.grid_height):
            for x in range(self.grid_width - 2):
                if self.grid[y][x] and self.grid[y][x] == self.grid[y][x+1] == self.grid[y][x+2]:
                    match_len = 3
                    while x + match_len < self.grid_width and self.grid[y][x] == self.grid[y][x+match_len]:
                        match_len += 1
                    matches.append([(x + i, y) for i in range(match_len)])

        # Vertical matches
        for x in range(self.grid_width):
            for y in range(self.grid_height - 2):
                if self.grid[y][x] and self.grid[y][x] == self.grid[y+1][x] == self.grid[y+2][x]:
                    match_len = 3
                    while y + match_len < self.grid_height and self.grid[y][x] == self.grid[y+match_len][x]:
                        match_len += 1
                    matches.append([(x, y + i) for i in range(match_len)])

        # Remove duplicate matches (matches sharing same gem)
        unique_matches = []
        for match in matches:
            if not any(coord in sum(unique_matches, []) for coord in match):
                unique_matches.append(match)
        return unique_matches

    def clear_matches(self, matches):
        cleared_count = 0
        for match in matches:
            cleared_count += len(match)
            for x, y in match:
                self.grid[y][x] = None  # Clear the gem
        return cleared_count

    def apply_gravity(self):
        for x in range(self.grid_width):
            empty_pos = None
            for y in range(self.grid_height):
                if self.grid[y][x] is None and empty_pos is None:
                    empty_pos = y
                elif self.grid[y][x] and empty_pos is not None:
                    self.grid[empty_pos][x] = self.grid[y][x]
                    self.grid[y][x] = None

                    # find next empty pos
                    new_empty_pos = empty_pos + 1
                    while new_empty_pos < self.grid_height and self.grid[new_empty_pos][x] is not None:
                        new_empty_pos += 1

                    if new_empty_pos < self.grid_height and self.grid[new_empty_pos][x] is None:
                        empty_pos = new_empty_pos
                    else:
                         empty_pos = None


    def handle_chain_reactions(self):
        total_score = 0
        chain_active = True
        while chain_active:
            matches = self.detect_matches()
            if matches:
                cleared_count = self.clear_matches(matches)
                self.apply_gravity()
                match_score = MATCH_CLEAR_SCORES.get(len(matches[0]), 200)  # Base score for a match
                chain_score = int(match_score * self.chain_multiplier)
                total_score += chain_score
                self.score += chain_score
                self.chain_multiplier *= CHAIN_BONUS_MULTIPLIER  # Increase multiplier for next chain

                #print(f"Chain reaction! Score: {chain_score}, Multiplier: {self.chain_multiplier}") #debug
            else:
                chain_active = False  # No more matches, chain ends
                self.chain_multiplier = 1.0  # Reset multiplier for the next piece

        return total_score # accumulated score

    def process_grid(self):
        matches = self.detect_matches()
        if matches:
            self.chain_reaction = True
            cleared_count = self.clear_matches(matches)
            self.apply_gravity()
            score_increase = self.handle_chain_reactions()  # includes match score
            #self.score += score_increase
        else:
            self.chain_reaction = False

    def lock_piece(self, piece, x, y, rotation_index):
        for point in TETROMINO_SHAPES[piece.piece_type][rotation_index]:
            grid_x = x + point.x
            grid_y = y + point.y
            if 0 <= grid_x < self.grid_width and 0 <= grid_y < self.grid_height:
                self.grid[grid_y][grid_x] = piece.color  # Gem color from piece

        self.process_grid()  # Check and clear matches after locking the piece

    def clear_lines(self):
        lines_to_clear = []
        for y in range(self.grid_height):
            if all(self.grid[y][x] is not None for x in range(self.grid_width)):
                lines_to_clear.append(y)

        if lines_to_clear:
            for y in lines_to_clear:
                del self.grid[y]
                self.grid.insert(0, [None] * self.grid_width)  # Add empty line at the top
            num_lines_cleared = len(lines_to_clear)
            self.score += LINE_CLEAR_SCORES.get(num_lines_cleared, 800) # score from line clearing

